  const N=v=>Number(String(v??0).replace(/,/g,''))||0;
  const A=v=>Array.isArray(v)?v:(v&&typeof v[Symbol.iterator]==='function'?[...v]:[]);
  const esc=v=>S(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const norm=v=>S(v).toLowerCase().replace(/[إأآا]/g,'ا').replace(/[ىي]/g,'ي').replace(/ة/g,'ه').replace(/[\u064B-\u0652]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();
  const db=()=>window.sb;
  const user=()=>{try{return JSON.parse(localStorage.getItem('tasneef_user')||'{}')||{};}catch(_){return{};}};
  const currentUserName=()=>S(user().full_name||user().name||user().username||'مستخدم النظام');
  const today=()=>{try{return new Intl.DateTimeFormat('en-CA',{timeZone:'Asia/Riyadh',year:'numeric',month:'2-digit',day:'2-digit'}).format(new Date());}catch(_){return new Date().toISOString().slice(0,10);}};
  const money=v=>N(v).toLocaleString('ar-SA',{minimumFractionDigits:2,maximumFractionDigits:2})+' ر.س';
  const daysTo=v=>{if(!v)return null;const a=new Date(today()+'T12:00:00'),b=new Date(S(v).slice(0,10)+'T12:00:00');return Math.round((b-a)/86400000);};
  const notify=(text,type='ok')=>{try{if(typeof window.msg==='function')return window.msg(text,type==='err'?'err':'ok');}catch(_){}; if(type==='err')console.error(text); else console.log(text);};
  const schemaError=e=>/project_contracts_unified|relation .* does not exist|schema cache|PGRST205|Could not find the table/i.test(S(e?.message||e));

  const CONTRACT_TYPES=['مصاعد','مسابح','دفاع مدني','خدمات سنوية','نظافة','صيانة عامة','مكافحة حشرات','غسيل خزانات','مضخات','كاميرات','بوابات وإنتركم','تكييف','تشجير','صيانة كهربائية','صيانة سباكة','أخرى'];
  const ADMIN_STATUSES=[['draft','مسودة'],['active','نشط'],['near_expiry','قريب الانتهاء'],['expired','منتهي'],['stopped','موقوف'],['cancelled','ملغي'],['renewing','تحت التجديد'],['renewed','تم التجديد'],['archived','مؤرشف'],['needs_review','يحتاج مراجعة']];
  const FREQS=['أسبوعي','نصف شهري','شهري','كل شهرين','ربع سنوي','نصف سنوي','سنوي','حسب الطلب'];
  const state={schema:null,providers:[],projects:[],contracts:[],page:1,pageSize:25,total:0,diagnostics:null,filters:{},currentProject:null,currentContract:null,loading:false};

  function can(action){
    const role=S(user().role).toLowerCase();
    if(['admin','system_admin','general_manager'].includes(role))return true;
    if(['operations_manager','contracts_officer'].includes(role))return !['migration'].includes(action);
    if(['financial_manager','finance_manager','accountant'].includes(role))return ['view','finance'].includes(action);
    if(role==='supervisor')return ['view','execute'].includes(action);
    return action==='view';
  }
  function projectName(id){return A(state.projects).find(p=>S(p.id)===S(id))?.name||A(window.data?.projects).find(p=>S(p.id)===S(id))?.name||'-';}
  function providerName(id,fallback=''){return A(state.providers).find(p=>S(p.id)===S(id))?.name||fallback||'-';}
  function administrativeLabel(v){return ADMIN_STATUSES.find(x=>x[0]===v)?.[1]||v||'-';}
  function temporalBadge(c){const d=N(c.days_remaining??daysTo(c.end_date));if(!c.end_date)return['amber','بيانات ناقصة'];if(d<0)return['red','منتهي'];if(d<=30)return['red',`ينتهي خلال ${d} يوم`];if(d<=60)return['amber',`ينتهي خلال ${d} يوم`];if(d<=90)return['amber',`ينتهي خلال ${d} يوم`];return['green','ساري'];}
